      await instructorAPI.createSlot({ date: selectedDate, start_time: startTime, end_time: endTime });
      onSaved();
    } catch(e) {
      setErr(e.response?.data?.detail || JSON.stringify(e.response?.data) || 'Ошибка');
    } finally { setLoading(false); }
